from typing import List

class Solution:
    def longestCommonPrefix(self, arr1: List[int], arr2: List[int]) -> int:
        # Use hashing of prefixes: for each number, add all its prefixes to a set,
        # then find the maximum length where a prefix from arr1 also appears in arr2.
        # Constraints are small enough for total digits up to ~3e6.

        def prefixes(num: int) -> List[str]:
            s = str(num)
            return [s[:i] for i in range(1, len(s) + 1)]

        set1 = set()
        max_len = 0
        for x in arr1:
            sx = str(x)
            max_len = max(max_len, len(sx))
            # add prefixes
            for i in range(1, len(sx) + 1):
                set1.add(sx[:i])

        ans = 0
        for y in arr2:
            sy = str(y)
            # check longest possible prefix first
            for i in range(len(sy), 0, -1):
                if sy[:i] in set1:
                    if i > ans:
                        ans = i
                    break
        return ans
