from typing import List

class Solution:
    def longestCommonPrefix(self, arr1: List[int], arr2: List[int]) -> int:
        # Build a trie for all numbers in arr1, then compute the maximum prefix length
        # that matches any number in arr2.
        class Node:
            __slots__ = ("nxt",)
            def __init__(self):
                self.nxt = {}  # digit(str) -> Node

        root = Node()

        def insert(num: int) -> None:
            s = str(num)
            node = root
            for ch in s:
                nxt = node.nxt.get(ch)
                if nxt is None:
                    nxt = Node()
                    node.nxt[ch] = nxt
                node = nxt

        for v in arr1:
            insert(v)

        best = 0
        for v in arr2:
            s = str(v)
            node = root
            cur = 0
            for ch in s:
                nxt = node.nxt.get(ch)
                if nxt is None:
                    break
                node = nxt
                cur += 1
            if cur > best:
                best = cur

        return best
