class Solution:
    def longestCommonPrefix(self, arr1: List[int], arr2: List[int]) -> int:
        # Build a set of all prefixes from arr1
        # Then check the longest prefix possible against arr2 numbers.
        pref = set()
        max_len = 0

        for x in arr1:
            s = str(x)
            max_len = max(max_len, len(s))
            for i in range(1, len(s) + 1):
                pref.add(s[:i])

        best = 0
        for y in arr2:
            s = str(y)
            # Try longest possible prefixes first
            # Stop early once we reach a found prefix.
            for i in range(len(s), 0, -1):
                if i <= best:
                    break
                if s[:i] in pref:
                    best = i
                    break

        return best
